Here's a modern MSTest approach using `MockHttpMessageHandler`, async test methods, and cancellation:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Async tests: just return Task — MSTest awaits them natively.
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // Timeout: use [Timeout] or a CancellationToken via TestContext.
    [TestMethod]
    [Timeout(3000)] // fails the test if it takes longer than 3 s
    public async Task FetchAsync_ThrowsOnHttpError()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // Cancellation: verify the token is respected.
    [TestMethod]
    public async Task FetchAsync_ThrowsWhenCancelled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new MockHttpMessageHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Helper: lightweight mock without external packages.
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode)
        {
            _content = content;
            _statusCode = statusCode;
        }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            var response = new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
            return Task.FromResult(response);
        }
    }
}
```

**Key patterns shown:**

| Pattern | Mechanism |
|---|---|
| **Async tests** | Return `Task` directly — MSTest awaits it; no `void`, no `.Result` |
| **Timeouts** | `[Timeout(ms)]` attribute fails the test if it exceeds the limit |
| **Cancellation** | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| **HTTP mocking** | Subclass `HttpMessageHandler` — no external mocking library needed |

> **Tip:** MSTest v3+ also exposes `TestContext.CancellationTokenSource` so `[Timeout]` cancels via a token you can forward into your SUT, giving cooperative cancellation instead of a hard thread abort.
